// client/src/services/assistantService.js
export async function askAssistant(query) {
  try {
    const resp = await fetch("/api/assistant", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ query }),
    });
    if (!resp.ok) throw new Error("Failed to reach AI assistant");
    const data = await resp.json();
    return data.reply;
  } catch (err) {
    console.error("Assistant service error:", err);
    return "Sorry, the assistant could not respond.";
  }
}
